var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 아마니 밸리. 코핀 컴퍼니 임시 지부 인근 착륙장.","JPN":"ロータス、アマニーバレー。コフィンカンパニーの臨時支部付近の着陸場。","ENG":"Lotus, Amani Valley. Landing strip near the temporary Coffin Company Branch.","TWN":"洛德斯，和平谷。科芬臨時分公司附近的停機坪。","SCN":"洛德斯，和平谷。科芬临时分公司附近的停机坪。","DEU":"Lotus, Amani Valley. Landing strip near the temporary Coffin Company Branch.","FRA":"Lotus, Amani Valley. Landing strip near the temporary Coffin Company Branch."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_1110311","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"몸은 좀 괜찮아졌나?","JPN":"体の調子はどうだ？","ENG":"Feeling any better?","TWN":"身體好點了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_1110311","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보다시피.","JPN":"見てのとおりだ。","ENG":"As you can see.","TWN":"正如你所見。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_1110311","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"피를 잔뜩 흘렸더니 오히려 홀가분해진 것 같기도 해.","JPN":"血をたくさん流したら、すっきりした気すらする。","ENG":"I do feel a bit relieved after losing a lot of blood.","TWN":"流了很多血，反而覺得輕鬆了些。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_1110311","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여태까지 난, 내가 피도 눈물도 없는 놈이 된 줄 알았는데 말이야.","JPN":"今まで私は、自分が血も涙もないやつだと思っていたのにな。","ENG":"I always thought that I was heartless.","TWN":"直到之前，我還以為自己是個沒血沒淚的人呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_1110311","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 성공에 필요하다면 자신이라도 걸겠다고 했었지.","JPN":"お前は成功のためなら自分自身も賭けると言ったな。","ENG":"You did say that you would risk your life if it meant pulling this off.","TWN":"你曾說過，為了成功你甚至願意賭上自己。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 말이 의미 그대로일 줄은 몰랐군.","JPN":"まさか言葉どおりの意味だったとは思わなかった。","ENG":"But I didn't think you meant it literally.","TWN":"我沒想到那句話會是字面的意思。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"고작 권총 하나로 뭘 하겠다고 잘난 듯이 사도를 가로막았던 거냐?","JPN":"たかが拳銃1丁で使徒に立ち向かうとは……どうするつもりだったんだ？","ENG":"Who in their right mind would confront an Apostle with just a pistol?","TWN":"你以為憑一把手槍就能擋住使徒嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 선택한 것 뿐일세.","JPN":"私は選択しただけさ。","ENG":"I just made a choice.","TWN":"只是我的選擇而已。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로의 마왕들… 그리고 탐미엘에게 대적하기 위해 가장 필요한 건, 내 잔꾀가 아니라 자네의 힘일 테니 말이야.","JPN":"これから魔王たち……そしてタミエルに立ち向かうために最も必要なのは、私の浅知恵ではない、君の力だからね。","ENG":"Because what we need most to fight against Tammiel and the Demon Lords that will soon come... is not my clever tricks, but your strength.","TWN":"今後要對抗魔王……還有塔米爾，最需要的不是我的小聰明，而是你的力量。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 질문을 한 게 아니다.","JPN":"別に質問をしたわけではない。","ENG":"It was a rhetorical question.","TWN":"我不是在問你問題。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다신 그런 멍청한 짓은 하지 말라는 뜻이지.","JPN":"2度とあんなバカなことはするなと言っているのだ。","ENG":"I meant to tell you to never do something that idiotic again.","TWN":"我的意思是今後不要再做那種蠢事了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…조심하겠네.","JPN":"……気をつけよう。","ENG":"...I'll be careful.","TWN":"……我會小心的。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자, 깨어났다고 들었어.","JPN":"最高管理者、目が覚めたって聞いた。","ENG":"I heard you woke up, Supreme Administrator.","TWN":"最高管理者，聽說你醒了。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 부탁한 <color=#ffd34c>전환기</color>의 프로토타입이 나와서 시험 가동을 해볼 건데. 참관할 거야?","JPN":"あなたに頼まれた<color=#ffd34c>転換器</color>のプロトタイプが完成して、テスト稼働をする予定だけど、見る？","ENG":"I was just about to test run the prototype of the <color=#ffd34c>converter</color> you requested. Care to join?","TWN":"你要求的<color=#ffd34c>變軌器</color>原型已經做出來了，我打算開始測試。你要來觀摩嗎？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…아파서 못 오는 거면 어쩔 수 없고.","JPN":"……怪我のせいで来れないなら、別にいい。","ENG":"...Even if you can't, it's all good.","TWN":"……如果是因為生病不能來，那也沒辦法。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 문제없네. 지금 가도록 하지.","JPN":"いや、問題ない。今向かおう。","ENG":"No, I'm good. I'll be right there.","TWN":"不，沒有問題。我馬上就來。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"파블린의 아이는… 어떻게 할 셈이지?","JPN":"パブリンの子どもは……どうする？","ENG":"What are you going to do... with Pavlin's child?","TWN":"帕芙琳的孩子……你打算怎麼辦？"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 우리가 겪어 나갈 풍파에 휘말리게 하고 싶진 않군.","JPN":"そうだな。これから私たちが飛び込む嵐に巻き込みたくはない。","ENG":"I'm not sure. But I don't want her to get caught in the storm we are about to undergo.","TWN":"嗯。我不想讓她捲入我們即將經歷的風暴之中。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국에서 보호하는 것도 나쁘지 않다고 생각하지만… 가장 중요한 건 본인의 의사겠지.","JPN":"管理局で保護するのも悪くないとは思うが……何より大事なのは本人の意思だ。","ENG":"It wouldn't be a bad idea for the Administration to protect her, but... what's most important is what she wants.","TWN":"雖然我覺得讓管理局保護她也不錯……但最重要的還是本人的意願吧。"},"stage":{"bg":"GAUNTLET","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"식사 시간이에요, 여러분.","JPN":"皆さん、食事の時間です。","ENG":"It's mealtime, everyone.","TWN":"吃飯囉，大家。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맛있는 음식, 그리고 꽃 한 송이씩 받아가세요.","JPN":"おいしい食べ物と、花を一輪ずつ受け取ってくださいね。","ENG":"Have some good food and get your flower too.","TWN":"請享用美食吧～還有，我為大家每個人都準備了一朵花～"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"고맙습니다, 언니.","JPN":"ありがとう、お姉ちゃん。","ENG":"Thank you.","TWN":"謝謝你，姊姊。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};